import anthropic
import json

client = anthropic.Anthropic()

# Define the desired output shape as a tool schema
EXTRACT_REVIEW_TOOL = {
    "name": "extract_review_analysis",
    "description": "Record the structured analysis of a product review.",
    "input_schema": {
        "type": "object",
        "properties": {
            "sentiment": {
                "type": "string",
                "enum": ["positive", "neutral", "negative"],
            },
            "pros": {
                "type": "array",
                "items": {"type": "string"},
                "minItems": 1,
                "description": "List of positive aspects mentioned.",
            },
            "cons": {
                "type": "array",
                "items": {"type": "string"},
                "description": "List of negative aspects mentioned.",
            },
            "score": {
                "type": "integer",
                "minimum": 1,
                "maximum": 5,
                "description": "Overall rating 1-5.",
            },
        },
        "required": ["sentiment", "pros", "cons", "score"],
    },
}


def analyse_review(review: str) -> dict:
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=300,
        tools=[EXTRACT_REVIEW_TOOL],
        tool_choice={"type": "tool", "name": "extract_review_analysis"},
        messages=[{
            "role": "user",
            "content": f"Analyse this product review:\n\n{review}",
        }],
    )
    for block in response.content:
        if block.type == "tool_use":
            return block.input  # already validated against the schema by the API
    raise RuntimeError("No tool call in response.")


result = analyse_review(
    "Sound quality is superb, but it broke after two months of light use."
)
print(json.dumps(result, indent=2))

