import anthropic
import json
from pydantic import BaseModel, validator
from typing import Optional
from datetime import date

client = anthropic.Anthropic()

# Define the exact output shape as both a Pydantic model and a tool schema
class ContractFields(BaseModel):
    party_a: str
    party_b: str
    effective_date: str   # ISO 8601 date string
    payment_days: int     # Net payment terms in days
    jurisdiction: str
    currency: str         # ISO 4217 code (USD, EUR, GBP)
    auto_renew: bool

    @validator('payment_days')
    def validate_payment_days(cls, v):
        if not 0 <= v <= 365:
            raise ValueError('payment_days must be between 0 and 365')
        return v

    @validator('currency')
    def validate_currency(cls, v):
        allowed = {'USD', 'EUR', 'GBP', 'JPY', 'CAD', 'AUD'}
        if v.upper() not in allowed:
            raise ValueError(f'currency must be one of {allowed}')
        return v.upper()


CONTRACT_TOOL = {
    "name": "extract_contract_fields",
    "description": "Extract structured fields from a legal contract.",
    "input_schema": {
        "type": "object",
        "properties": {
            "party_a":        {"type": "string", "description": "First party full legal name"},
            "party_b":        {"type": "string", "description": "Second party full legal name"},
            "effective_date": {"type": "string", "description": "ISO 8601 date (YYYY-MM-DD)"},
            "payment_days":   {"type": "integer", "minimum": 0, "maximum": 365},
            "jurisdiction":   {"type": "string", "description": "Governing law jurisdiction"},
            "currency":       {"type": "string", "description": "ISO 4217 currency code"},
            "auto_renew":     {"type": "boolean"},
        },
        "required": ["party_a", "party_b", "effective_date", "payment_days",
                     "jurisdiction", "currency", "auto_renew"],
    }
}


def extract_contract(contract_text: str) -> ContractFields:
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=500,
        tools=[CONTRACT_TOOL],
        tool_choice={"type": "tool", "name": "extract_contract_fields"},
        messages=[{
            "role": "user",
            "content": f"Extract the structured fields from this contract:\n\n{contract_text}"
        }]
    )
    for block in response.content:
        if block.type == "tool_use":
            # API guarantees JSON Schema compliance; Pydantic adds business-rule validation
            return ContractFields(**block.input)
    raise RuntimeError("No tool call in response")


SAMPLE = """
This Service Agreement ("Agreement") is entered into as of January 15, 2025,
between Acme Corporation, a Delaware corporation ("Party A"), and Globex Ltd,
an English company ("Party B"). Payment is due within 30 days of invoice.
This Agreement is governed by the laws of New York. All amounts in USD.
This Agreement auto-renews annually unless terminated with 60 days notice.
"""

result = extract_contract(SAMPLE)
print(json.dumps(result.dict(), indent=2))
